/**
 * 前端性能监控
 *
 * 采集指标：白屏时间、API P95 响应时间、FPS、内存占用
 * 上报策略：每 30s 汇总一次 → 批量上报
 *
 * 使用方式：
 *   import perfMonitor from '@/common/perfMonitor.js'
 *   perfMonitor.init()              // App.onLaunch
 *   perfMonitor.markApiStart(id)    // API 请求开始
 *   perfMonitor.markApiEnd(id)      // API 请求结束
 */
'use strict'

const REPORT_INTERVAL = 30000 // 30s

class PerfMonitor {
  constructor() {
    this._apiTimings = []        // { name, duration }
    this._fpsSamples = []
    this._launchTime = Date.now()
    this._firstRenderDone = false
    this._apiInFlight = new Map() // id → startTime
    this._timer = null
    this._fpsRunning = false      // FPS 采样控制开关
    this._appInForeground = true  // App 前后台状态
  }

  /** 初始化 */
  init() {
    this._startReportTimer()
    this._startFpsSampling()
    this._recordLaunchTime()
    this._listenAppLifecycle()
  }

  /** 标记首屏渲染完成 (在首页 onReady 中调用) */
  markFirstRender() {
    if (this._firstRenderDone) return
    this._firstRenderDone = true
    const ttfr = Date.now() - this._launchTime
    this._report('perf_first_render', { ttfr })
  }

  /** API 请求开始 */
  markApiStart(requestId, apiName = '') {
    this._apiInFlight.set(requestId, { start: Date.now(), name: apiName })
  }

  /** API 请求结束 */
  markApiEnd(requestId) {
    const entry = this._apiInFlight.get(requestId)
    if (!entry) return
    this._apiInFlight.delete(requestId)
    const duration = Date.now() - entry.start
    this._apiTimings.push({ name: entry.name, duration })
    // 保留最近 200 条
    if (this._apiTimings.length > 200) this._apiTimings.shift()
  }

  /** 计算 API 响应时间 P95 */
  getApiP95() {
    if (!this._apiTimings.length) return 0
    const sorted = this._apiTimings.map(t => t.duration).sort((a, b) => a - b)
    const idx = Math.floor(sorted.length * 0.95)
    return sorted[Math.min(idx, sorted.length - 1)]
  }

  /** 获取平均 FPS */
  getAvgFps() {
    if (!this._fpsSamples.length) return 60
    const sum = this._fpsSamples.reduce((s, v) => s + v, 0)
    return Math.round(sum / this._fpsSamples.length)
  }

  /** 获取内存占用 (仅 APP 端) */
  getMemoryUsage() {
    // #ifdef APP-PLUS
    try {
      const info = plus.runtime.getProperty(plus.runtime.appid, () => {})
      // plus.memory 并非标准 API，使用 performance 兜底
    } catch (_) { /* ignore */ }
    // #endif
    // 通用：使用 uni.getSystemInfoSync 估算
    try {
      const info = uni.getSystemInfoSync()
      return {
        deviceMemory: info.deviceMemory || 0,
      }
    } catch (_) {
      return {}
    }
  }

  // ─── 内部方法 ───

  _recordLaunchTime() {
    // 白屏率指标：记录 App 启动时间点
    this._report('perf_launch', {
      launchTime: this._launchTime,
      cold: true,
    })
  }

  _startFpsSampling() {
    // FPS 采样：仅在支持 requestAnimationFrame 的平台 (H5/APP)
    // 通过 _fpsRunning 标志位控制，destroy / App 进入后台时停止
    // #ifdef H5 || APP-PLUS
    if (this._fpsRunning) return
    this._fpsRunning = true
    let lastTime = Date.now()
    let frameCount = 0
    const measure = () => {
      if (!this._fpsRunning) return // ← 停止递归
      frameCount++
      const now = Date.now()
      if (now - lastTime >= 1000) {
        this._fpsSamples.push(frameCount)
        if (this._fpsSamples.length > 60) this._fpsSamples.shift()
        frameCount = 0
        lastTime = now
      }
      if (typeof requestAnimationFrame === 'function') {
        requestAnimationFrame(measure)
      }
    }
    if (typeof requestAnimationFrame === 'function') {
      requestAnimationFrame(measure)
    }
    // #endif
  }

  /** 停止 FPS 采样 */
  _stopFpsSampling() {
    this._fpsRunning = false
  }

  /** 监听 App 前后台切换，后台时暂停采集节省资源 */
  _listenAppLifecycle() {
    try {
      uni.onAppShow && uni.onAppShow(() => {
        this._appInForeground = true
        this._startFpsSampling()
        this._startReportTimer()
      })
      uni.onAppHide && uni.onAppHide(() => {
        this._appInForeground = false
        this._stopFpsSampling()
        // 暂停定时上报
        if (this._timer) {
          clearInterval(this._timer)
          this._timer = null
        }
      })
    } catch (_) {
      // 部分平台不支持 onAppShow/onAppHide，静默忽略
    }
  }

  _startReportTimer() {
    if (this._timer) return
    this._timer = setInterval(() => this._periodicReport(), REPORT_INTERVAL)
  }

  async _periodicReport() {
    const metrics = {
      apiP95: this.getApiP95(),
      avgFps: this.getAvgFps(),
      memory: this.getMemoryUsage(),
      apiCount: this._apiTimings.length,
      timestamp: Date.now(),
    }
    this._report('perf_metrics', metrics)
  }

  async _report(type, data) {
    try {
      await uniCloud.callFunction({
        name: 'fit-ucenter-api',
        data: {
          action: 'reportPerf',
          params: { type, ...data },
        },
      })
    } catch (_) {
      // 静默失败：不影响用户体验
    }
  }

  destroy() {
    this._stopFpsSampling()
    if (this._timer) {
      clearInterval(this._timer)
      this._timer = null
    }
  }
}

const perfMonitor = new PerfMonitor()
export default perfMonitor

/**
 * 微信小程序静默登录 code 预取工具
 * - 启动时预取并缓存 code，4 分钟内可复用
 * - 登录时通过 getFreshWxCode 获取最新 code（过期自动刷新）
 * - 非微信小程序环境返回空字符串
 */

const CODE_TTL = 4 * 60 * 1000;
const DEFAULT_RETRY = 2;

let cachedCode = '';
let expiresAt = 0;
let inflight = null;
let lastWxCodeMeta = {
	platform: '',
	attempt: 0,
	retryBudget: 0,
	codePresent: false,
	codeLength: 0,
	errMsg: '',
	timestamp: 0,
};

function getRuntimePlatform() {
	try {
		return typeof process !== 'undefined' && process.env ? process.env.UNI_PLATFORM || 'unknown' : 'unknown';
	} catch (_) {
		return 'unknown';
	}
}

function updateWxCodeMeta(payload = {}) {
	lastWxCodeMeta = {
		...lastWxCodeMeta,
		platform: getRuntimePlatform(),
		timestamp: Date.now(),
		...payload,
	};
}

function hasNativeWxLogin() {
	try {
		return typeof wx !== 'undefined' && !!wx && typeof wx.login === 'function';
	} catch (_) {
		return false;
	}
}

function isMpWeixin() {
	try {
		const platform = typeof process !== 'undefined' && process.env ? process.env.UNI_PLATFORM : '';
		return (typeof uni !== 'undefined' && platform === 'mp-weixin') || hasNativeWxLogin();
	} catch (_) {
		return hasNativeWxLogin();
	}
}

function isFresh() {
	return cachedCode && expiresAt - Date.now() > 60 * 1000;
}

function wait(ms) {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

function logWxLogin(event, payload = {}) {
	if (!isMpWeixin()) return;
	console.info(`[auth][wx-login] ${event}`, {
		platform: getRuntimePlatform(),
		...payload,
	});
}

function normalizeOptions(forceOrOptions, maybeRetry) {
	if (forceOrOptions && typeof forceOrOptions === 'object') {
		const retry = Number.isInteger(forceOrOptions.retry) ? Math.max(0, forceOrOptions.retry) : DEFAULT_RETRY;
		return {
			force: !!forceOrOptions.force,
			retry,
		};
	}
	return {
		force: !!forceOrOptions,
		retry: Number.isInteger(maybeRetry) ? Math.max(0, maybeRetry) : DEFAULT_RETRY,
	};
}

function requestWxCodeByUni(attempt = 0) {
	return new Promise((resolve) => {
		if (typeof uni === 'undefined' || typeof uni.login !== 'function') {
			resolve({
				code: '',
				reason: 'uni.login unavailable',
			});
			return;
		}
		uni.login({
			provider: 'weixin',
			success: (res) => {
				resolve({
					code: (res && res.code) || '',
					reason: (res && res.errMsg) || '',
				});
			},
			fail: (err) => {
				resolve({
					code: '',
					reason: (err && (err.errMsg || err.message)) || '',
				});
			},
		});
	});
}

function requestWxCodeByNative(attempt = 0) {
	return new Promise((resolve) => {
		if (!hasNativeWxLogin()) {
			resolve({
				code: '',
				reason: 'wx.login unavailable',
			});
			return;
		}
		wx.login({
			success: (res) => {
				resolve({
					code: (res && res.code) || '',
					reason: (res && res.errMsg) || '',
				});
			},
			fail: (err) => {
				resolve({
					code: '',
					reason: (err && (err.errMsg || err.message)) || '',
				});
			},
		});
	});
}

async function requestWxCodeOnce(attempt = 0) {
	const uniResult = await requestWxCodeByUni(attempt);
	if (uniResult.code) {
		updateWxCodeMeta({
			attempt: attempt + 1,
			codePresent: true,
			codeLength: uniResult.code.length,
			errMsg: uniResult.reason,
		});
		logWxLogin('uni.login success', {
			attempt: attempt + 1,
			codePresent: true,
			codeLength: uniResult.code.length,
			errMsg: uniResult.reason,
		});
		return uniResult;
	}

	const nativeResult = await requestWxCodeByNative(attempt);
	const mergedReason = [uniResult.reason, nativeResult.reason].filter(Boolean).join(' | ');
	const finalResult = nativeResult.code ? nativeResult : { code: '', reason: mergedReason };
	updateWxCodeMeta({
		attempt: attempt + 1,
		codePresent: !!finalResult.code,
		codeLength: finalResult.code ? finalResult.code.length : 0,
		errMsg: finalResult.reason,
	});
	logWxLogin(finalResult.code ? 'wx.login success' : 'wx.login empty code', {
		attempt: attempt + 1,
		codePresent: !!finalResult.code,
		codeLength: finalResult.code ? finalResult.code.length : 0,
		errMsg: finalResult.reason,
	});
	return finalResult;
}

async function fetchWxCodeWithRetry(retry = DEFAULT_RETRY) {
	let lastReason = '';
	for (let attempt = 0; attempt <= retry; attempt += 1) {
		const { code, reason } = await requestWxCodeOnce(attempt);
		if (code) {
			cachedCode = code;
			expiresAt = Date.now() + CODE_TTL;
			updateWxCodeMeta({
				attempt: attempt + 1,
				retryBudget: retry,
				codePresent: true,
				codeLength: code.length,
				errMsg: '',
			});
			logWxLogin('code cached', {
				attempt: attempt + 1,
				retryBudget: retry,
				codePresent: true,
				codeLength: code.length,
			});
			return code;
		}
		lastReason = reason || 'uni.login returned empty code';
		updateWxCodeMeta({
			attempt: attempt + 1,
			retryBudget: retry,
			codePresent: false,
			codeLength: 0,
			errMsg: lastReason,
		});
		logWxLogin('uni.login empty code', {
			attempt: attempt + 1,
			retryBudget: retry,
			codePresent: false,
			codeLength: 0,
			errMsg: lastReason,
		});
		if (attempt < retry) {
			await wait(120 * (attempt + 1));
		}
	}
	clearWxCode();
	console.warn('[auth] failed to get wx login code after retry:', lastReason);
	return '';
}

export function clearWxCode() {
	cachedCode = '';
	expiresAt = 0;
}

export function getWxCodeDebugInfo() {
	return {
		...lastWxCodeMeta,
		hasCachedCode: !!cachedCode,
		cacheExpiresInMs: Math.max(0, expiresAt - Date.now()),
	};
}

export function getCachedWxCode() {
	if (!isFresh()) return '';
	return cachedCode;
}

export function consumeWxCode() {
	if (!cachedCode) return '';
	const code = cachedCode;
	clearWxCode();
	return code;
}

export async function prefetchWxCode(forceOrOptions = false, maybeRetry) {
	if (!isMpWeixin()) return '';
	const { force, retry } = normalizeOptions(forceOrOptions, maybeRetry);
	if (!force && isFresh()) {
		logWxLogin('reuse cached code', {
			codePresent: true,
			codeLength: cachedCode.length,
		});
		return cachedCode;
	}
	if (inflight) {
		logWxLogin('await inflight code request');
		return inflight;
	}

	inflight = fetchWxCodeWithRetry(retry).finally(() => {
		inflight = null;
	});
	return inflight;
}

export async function getFreshWxCode(options) {
	if (!isMpWeixin()) return '';
	const { force, retry } = normalizeOptions(options || {}, DEFAULT_RETRY);
	if (!force && isFresh()) {
		logWxLogin('getFreshWxCode hit cache', {
			codePresent: true,
			codeLength: cachedCode.length,
		});
		return cachedCode;
	}
	await prefetchWxCode({ force: true, retry });
	return cachedCode;
}

import langEn from './en'
import zhHans from './zh-Hans'
import uniStarterConfig from '../uni-starter.config.js'
const {i18n:{enable:i18nEnable} }= uniStarterConfig
const messages = {
	'en': langEn,
	'zh-Hans': zhHans
}
let currentLang
if(i18nEnable){
	currentLang = uni.getStorageSync('CURRENT_LANG')
}else{
	currentLang = "zh-Hans"
}
// console.log(uni.getStorageSync('CURRENT_LANG'),currentLang);
if (!currentLang) {
	if (uni.getLocale) {
		console.log('获取应用语言:', uni.getLocale());
		let language = 'en'
		if (uni.getLocale() != 'en') {
			language = 'zh-Hans'
		}
		uni.setStorageSync('CURRENT_LANG', language)
		currentLang = language
	} else {
		uni.getSystemInfo({
			success: function(res) {
				console.log('获取设备信息:', res);
				let language = 'zh-Hans'
				if (res.language == 'en') {
					language = 'en'
				}
				uni.setStorageSync('CURRENT_LANG', language)
				currentLang = language
			},
			fail: (err) => {
				console.error(err)
			}
		})
	}
}
const i18nConfig = {
	locale: currentLang, // set locale
	messages // set locale messages
}
let i18n

// #ifdef VUE2
import Vue from 'vue'
import VueI18n from 'vue-i18n'
Vue.use(VueI18n)
i18n = new VueI18n(i18nConfig)
// #endif

// #ifdef VUE3
import {
	createI18n
} from 'vue-i18n'
i18n = createI18n(i18nConfig)
// #endif

export default i18n


if(i18nEnable){
console.log(`
	你已开启多语言国际化，将自动根据语言获取【lang/en.js】或【lang/en.js】文件中配置的tabbar的值，
	覆盖你在pages.json中的tabbar的值
	如果你不需要多语言国际化，请打开配置文件uni-starter.config.js找到 -> i18n -> enable把值设置为false
`);
	const initLanguageAfter = () => {
		function $i18n(e){
			if (i18n && i18n.global && i18n.global.messages) {
				return i18n.global.messages[i18n.global.locale][e]
			}
			return i18n.messages[i18n.locale][e]
		}
		setTimeout(function(){
			//底部tabbar更新
			$i18n('tabbar').split(',').forEach((text, index) => {
				// console.log(text);
				uni.setTabBarItem({
					index,
					text,
					complete: e => {
						// console.log("e: " + JSON.stringify(e));
					}
				})
			})
		},1)
	}
	initLanguageAfter()
	uni.$on('changeLanguage', e => {
		console.log('changeLanguage', e);
		initLanguageAfter(e)
	})
}

﻿<template>
	<view class="login-page">
		<view class="login-shell">
			<view class="brand-section" role="banner">
				<text class="brand-kicker">FIT TRAINING</text>
				<image class="brand-logo" src="/static/logo.png" mode="aspectFit" aria-hidden="true"></image>
				<text class="brand-name">FIT</text>
				<text class="brand-slogan">{{ $t('login.page.entrySlogan') }}</text>
			</view>

			<view class="login-card">
				<view class="login-tabs" role="tablist" :aria-label="$t('login.page.tabsLabel')">
					<view class="login-tab" :class="{ active: activeTab === 'sms' }" role="tab" :aria-selected="activeTab === 'sms'" @click="switchTab('sms')">
						{{ $t('login.page.smsTab') }}
					</view>
					<view class="login-tab" :class="{ active: activeTab === 'pwd' }" role="tab" :aria-selected="activeTab === 'pwd'" @click="switchTab('pwd')">
						{{ $t('login.page.pwdTab') }}
					</view>
				</view>

				<view v-if="activeTab === 'sms'" class="tab-panel">
					<view class="input-box">
						<uni-easyinput
							v-model="smsPhone"
							trim="both"
							maxlength="11"
							type="number"
							:input-border="false"
							:placeholder="$t('login.page.withoutPwd.phonePlaceholder')"
						/>
					</view>
					<uni-id-pages-sms-form
						ref="smsForm"
						v-model="smsCode"
						type="login-by-sms"
						:phone="smsPhone"
						focus-captcha-input
					/>
					<view class="agreements-wrap">
						<uni-id-pages-agreements ref="agreements" scope="login"></uni-id-pages-agreements>
					</view>
					<button class="btn-primary" @click="submitSmsLogin">{{ $t('login.page.loginAction') }}</button>
				</view>

				<view v-else class="tab-panel">
					<view class="input-box">
						<uni-easyinput
							v-model="username"
							trim="both"
							:input-border="false"
							:placeholder="$t('login.page.pwd.usernamePlaceholder')"
						/>
					</view>
					<view class="input-box">
						<uni-easyinput
							v-model="password"
							trim="both"
							type="password"
							:input-border="false"
							:placeholder="$t('login.page.pwd.passwordPlaceholder')"
						/>
					</view>
					<uni-captcha v-if="needPwdCaptcha" ref="pwdCaptcha" scene="login-by-pwd" v-model="pwdCaptcha" />
					<view class="agreements-wrap">
						<uni-id-pages-agreements ref="agreements" scope="login"></uni-id-pages-agreements>
					</view>
					<button class="btn-primary" @click="submitPwdLogin">{{ $t('login.page.loginAction') }}</button>
					<view class="link-row">
						<text class="link-text" @click="openRetrieve">{{ $t('login.page.pwd.retrieve') }}</text>
						<text class="link-text" @click="openRegister">{{ $t('login.page.pwd.register') }}</text>
					</view>
				</view>

				<!-- #ifdef MP-WEIXIN -->
					<button class="btn-wx-login" :loading="wxLoginLoading" :disabled="wxLoginLoading" @click="doWeixinLogin">
						{{ $t('login.page.withoutPwd.weixinPrimary') }}
					</button>
				<!-- #endif -->
			</view>
		</view>

		<uni-popup-captcha ref="smsLoginCaptchaPopup" v-model="smsCaptcha" scene="login-by-sms" @confirm="submitSmsLogin"></uni-popup-captcha>
	</view>
</template>

<script>
import mixin from '@/uni_modules/uni-id-pages/common/login-page.mixin.js';
import { safeHideLoading } from '@/common/uiLoading.js';
import { getFreshWxCode, getWxCodeDebugInfo } from '@/common/wxSilentLogin.js';
import { useUserStore } from '@/store/user.js';

const uniIdCo = uniCloud.importObject('uni-id-co', {
	customUI: true,
});

export default {
	mixins: [mixin],
	data() {
		return {
			activeTab: 'sms',
			smsPhone: '',
			smsCode: '',
			smsCaptcha: '',
			username: '',
			password: '',
			pwdCaptcha: '',
			needPwdCaptcha: false,
			wxLoginLoading: false,
		};
	},
	onLoad(options = {}) {
		const tab = String(options.tab || '').toLowerCase();
		if (tab === 'pwd' || tab === 'password') {
			this.activeTab = 'pwd';
		}
		if (tab === 'sms') {
			this.activeTab = 'sms';
		}
		if (options.phoneNumber) {
			this.smsPhone = String(options.phoneNumber);
		}
	},
	onShow() {
		// #ifdef H5
		document.onkeydown = (event) => {
			const e = event || window.event;
			if (e && e.keyCode === 13) {
				if (this.activeTab === 'sms') {
					this.submitSmsLogin();
				} else {
					this.submitPwdLogin();
				}
			}
		};
		// #endif
	},
	methods: {
		switchTab(tab) {
			if (tab !== 'sms' && tab !== 'pwd') return;
			this.activeTab = tab;
		},
		ensureAgreement(callback) {
			if (this.needAgreements && !this.agree) {
				this.$refs.agreements && this.$refs.agreements.popup(callback);
				return false;
			}
			return true;
		},
		showLoginFailure(message) {
			uni.showModal({
				title: this.$t('login.page.loginFailedTitle'),
				content: message || this.$t('login.page.genericRetry'),
				showCancel: false,
			});
		},
		async submitSmsLogin() {
			if (!/^1\d{10}$/.test(this.smsPhone)) {
				uni.showToast({ title: this.$t('login.page.withoutPwd.invalidPhone'), icon: 'none' });
				return;
			}
			if (String(this.smsCode || '').length !== 6) {
				uni.showToast({ title: this.$t('login.page.sms.codeRequired'), icon: 'none' });
				return;
			}
			if (!this.ensureAgreement(this.submitSmsLogin)) return;
			try {
				const res = await uniIdCo.loginBySms({
					mobile: this.smsPhone,
					code: this.smsCode,
					captcha: this.smsCaptcha,
				});
				this.loginSuccess({ ...(res || {}), autoBack: false });
			} catch (error) {
				if (error && error.errCode === 'uni-id-captcha-required') {
					this.$refs.smsLoginCaptchaPopup && this.$refs.smsLoginCaptchaPopup.open();
					return;
				}
				this.showLoginFailure((error && (error.message || error.errMsg)) || this.$t('login.page.genericRetry'));
			} finally {
				this.smsCaptcha = '';
			}
		},
		buildPwdLoginPayload() {
			const payload = {
				password: this.password,
				captcha: this.pwdCaptcha,
			};
			if (/^1\d{10}$/.test(this.username)) {
				payload.mobile = this.username;
			} else if (/@/.test(this.username)) {
				payload.email = this.username;
			} else {
				payload.username = this.username;
			}
			return payload;
		},
		async submitPwdLogin() {
			if (!this.username) {
				uni.showToast({ title: this.$t('login.page.pwd.accountRequired'), icon: 'none' });
				return;
			}
			if (!this.password) {
				uni.showToast({ title: this.$t('login.page.pwd.passwordRequired'), icon: 'none' });
				return;
			}
			if (this.needPwdCaptcha && String(this.pwdCaptcha || '').length !== 4) {
				this.$refs.pwdCaptcha && this.$refs.pwdCaptcha.getImageCaptcha();
				uni.showToast({ title: this.$t('login.page.pwd.imageCaptchaRequired'), icon: 'none' });
				return;
			}
			if (!this.ensureAgreement(this.submitPwdLogin)) return;
			try {
				const res = await uniIdCo.login(this.buildPwdLoginPayload());
				this.loginSuccess({ ...(res || {}), autoBack: false });
			} catch (error) {
				if (error && error.errCode === 'uni-id-captcha-required') {
					this.needPwdCaptcha = true;
					this.$nextTick(() => {
						this.$refs.pwdCaptcha && this.$refs.pwdCaptcha.getImageCaptcha();
					});
					return;
				}
				if (this.needPwdCaptcha && this.$refs.pwdCaptcha) {
					this.$refs.pwdCaptcha.getImageCaptcha();
				}
				this.showLoginFailure((error && (error.message || error.errMsg)) || '密码登录失败');
			}
		},
		async doWeixinLogin() {
			if (!this.ensureAgreement(this.doWeixinLogin)) return;
			if (this.wxLoginLoading) return;
			this.wxLoginLoading = true;
			uni.showLoading({ title: this.$t('login.page.loading'), mask: true });
			try {
				const code = await getFreshWxCode({ force: true, retry: 3 });
				const wxCodeDebug = getWxCodeDebugInfo();
				console.info('[login] wx code fetch completed', {
					codePresent: !!code,
					codeLength: code ? code.length : 0,
					...wxCodeDebug,
				});
				if (!code) throw new Error(this.$t('login.page.withoutPwd.missingWxCode'));
				const res = await uniIdCo.loginByWeixin({ code });
				this.loginSuccess({ ...(res || {}), autoBack: false });
				const userStore = useUserStore();
				userStore.syncFromLogin();
			} catch (error) {
				uni.showModal({
					title: this.$t('login.page.loginFailedTitle'),
					content: (error && (error.message || error.errMsg)) || this.$t('login.page.genericRetry'),
					showCancel: false,
				});
			} finally {
				await safeHideLoading();
				this.wxLoginLoading = false;
			}
		},
		openRegister() {
			uni.navigateTo({ url: '/uni_modules/uni-id-pages/pages/register/register' });
		},
		openRetrieve() {
			let url = '/uni_modules/uni-id-pages/pages/retrieve/retrieve';
			if (/^1\d{10}$/.test(this.username)) {
				url += `?phoneNumber=${this.username}`;
			}
			uni.navigateTo({ url });
		},
	},
};
